-- [SELF JOIN ] --
-- 1. Find employees along with their manager names.
select e.emp_name as Employee, m.emp_name as Manager
from employees e left join employees m
on e.manager_id = m.emp_id;

-- 2. Display employees who earn more than their managers.
select e.emp_name
from employees e inner join employees m
on e.manager_id = m.emp_id
where e.salary > m.salary;

-- 3. Find employees working in the same department as their manager.
select e.emp_name
from employees e inner join employees m
on e.manager_id = m.emp_id
where e.dept_id = m.dept_id;

-- 4. Show all employee pairs working in the same department.
select e1.emp_name, e2.emp_name, e1.dept_id
from employees e1 inner join employees e2
on e1.dept_id = e2.dept_id
and e1.emp_id <> e2.emp_id;

-- 5. Find employees who joined earlier than their managers.
select e1.emp_name as Employee, e2.emp_name as Manager, e1.hire_date
from employees e1 inner join employees e2
on e1.manager_id = e2.emp_id
where e1.hire_date < e2.hire_date;

-- 6. Display employees and their manager salaries.
select e1.emp_name as Employee, e2.salary as "Manager's Salary"
from employees e1 inner join employees e2
on e1.manager_id = e2.emp_id;

-- 7. Find employees whose manager is from the HR department.
select e1.emp_name as Employee, e2.emp_name as Manager, d.dept_name
from employees e1 inner join employees e2 on e1.manager_id = e2.emp_id
left join departments d on e2.dept_id = d.dept_id
where d.dept_name = "HR";

-- 8. List employees who do not have managers.
select e1.emp_name as Employee, e2.emp_name as Manager
from employees e1 left join employees e2
on e1.manager_id = e2.emp_id
where e1.manager_id is null;

-- 9. Find manager names with the number of employees under them.
select distinct e2.emp_name, count(*) as emp_count
from employees e1 inner join employees e2
on e1.manager_id = e2.emp_id
group by e1.manager_id;

-- 10. Display employees having the same salary as their managers.
select e1.emp_name as Employee, e1.salary as "Employee's Salary",
e2.emp_name as Manager, e2.salary as "Manager's Salary"
from employees e1 inner join employees e2
on e1.manager_id = e2.emp_id
where e1.salary = e2.salary;

-- 11. Find employees whose manager joined in the same year.
select e1.emp_name, e1.hire_date, e2.emp_name, e2.hire_date
from employees e1 inner join employees e2
on e1.manager_id = e2.emp_id
where e1.hire_date = e2.hire_date;

-- 12. Show hierarchy levels up to manager’s manager.
select e1.emp_name as Employee, e2.emp_name as Manager, e3.emp_name as "Manager's Manager Name"
from employees e1 left join employees e2 on e1.manager_id = e2.emp_id
left join employees e3 on e2.manager_id = e3.emp_id;


-- [LEFT JOIN] -- 

-- 13. Display all employees and their department names.
select e.emp_name, d.dept_name
from employees e left join departments d
on e.dept_id = d.dept_id;

-- 14. Show all departments even if no employees exist.
select e.emp_name, d.dept_name
from employees e right join departments d
on e.dept_id = d.dept_id;

-- 15. Find employees without departments.
select e.emp_name
from employees e left join departments d
on e.dept_id = d.dept_id
where d.dept_id is null;

